import{_ as a,c as o,o as t,a1 as r}from"./chunks/framework.DILC4Csi.js";const h=JSON.parse('{"title":"Solução de Erro 401: Falha de Autenticação | Antigravity-Manager","description":"Aprenda o mecanismo de autenticação do proxy do Antigravity Tools, resolva erros 401. Localize o problema seguindo a ordem auth_mode, api_key, Header, entenda as regras do modo auto e a isenção /healthz, evite erros de prioridade de Header.","frontmatter":{"title":"Solução de Erro 401: Falha de Autenticação | Antigravity-Manager","sidebarTitle":"Resolva 401 em 3 Minutos","subtitle":"401/Falha de Autenticação: Verifique auth_mode Primeiro, Depois Headers","description":"Aprenda o mecanismo de autenticação do proxy do Antigravity Tools, resolva erros 401. Localize o problema seguindo a ordem auth_mode, api_key, Header, entenda as regras do modo auto e a isenção /healthz, evite erros de prioridade de Header.","tags":["FAQ","Autenticação","401","API Key"],"prerequisite":["start-proxy-and-first-client"],"order":2},"headers":[],"relativePath":"pt/lbjlaq/Antigravity-Manager/faq/auth-401/index.md","filePath":"pt/lbjlaq/Antigravity-Manager/faq/auth-401/index.md"}'),i={name:"pt/lbjlaq/Antigravity-Manager/faq/auth-401/index.md"};function d(s,e,c,l,n,u){return t(),o("div",null,[...e[0]||(e[0]=[r('<h1 id="_401-falha-de-autenticacao-verifique-auth-mode-primeiro-depois-headers" tabindex="-1">401/Falha de Autenticação: Verifique auth_mode Primeiro, Depois Headers <a class="header-anchor" href="#_401-falha-de-autenticacao-verifique-auth-mode-primeiro-depois-headers" aria-label="Permalink to &quot;401/Falha de Autenticação: Verifique auth_mode Primeiro, Depois Headers&quot;">​</a></h1><h2 id="o-que-voce-podera-fazer-apos-este-curso" tabindex="-1">O Que Você Poderá Fazer Após Este Curso <a class="header-anchor" href="#o-que-voce-podera-fazer-apos-este-curso" aria-label="Permalink to &quot;O Que Você Poderá Fazer Após Este Curso&quot;">​</a></h2><ul><li>Determinar em 3 minutos se o 401 está sendo bloqueado pelo middleware de autenticação do Antigravity Tools</li><li>Entender o &quot;valor efetivo&quot; dos quatro modos de <code>proxy.auth_mode</code> (especialmente <code>auto</code>) na sua configuração atual</li><li>Fazer solicitações passarem usando o Header de API Key correto (e evitando a armadilha de prioridade de Headers)</li></ul><h2 id="seu-problema-atual" tabindex="-1">Seu Problema Atual <a class="header-anchor" href="#seu-problema-atual" aria-label="Permalink to &quot;Seu Problema Atual&quot;">​</a></h2><p>Ao chamar o proxy reverso local pelo cliente, você recebe o erro <code>401 Unauthorized</code>:</p><ul><li>Python/OpenAI SDK: lança <code>AuthenticationError</code></li><li>curl: retorna <code>HTTP/1.1 401 Unauthorized</code></li><li>Cliente HTTP: código de status da resposta 401</li></ul><h2 id="o-que-e-401-falha-de-autenticacao" tabindex="-1">O Que é 401/Falha de Autenticação? <a class="header-anchor" href="#o-que-e-401-falha-de-autenticacao" aria-label="Permalink to &quot;O Que é 401/Falha de Autenticação?&quot;">​</a></h2><p><strong>401 Unauthorized</strong> no Antigravity Tools geralmente significa: o proxy habilitou autenticação (determinado por <code>proxy.auth_mode</code>), mas a solicitação não carregou uma API Key correta, ou carregou um Header com prioridade mais alta mas incorreto, então <code>auth_middleware()</code> retorna diretamente 401.</p><div class="info custom-block"><p class="custom-block-title">Primeiro Confirme se É &quot;o Proxy Bloqueando&quot;</p><p>O upstream também pode retornar 401, mas este FAQ só lida com &quot;401 causado pela autenticação do proxy&quot;. Você pode primeiro usar <code>/healthz</code> abaixo para distinguir rapidamente.</p></div><h2 id="solucao-rapida-faca-nesta-ordem" tabindex="-1">Solução Rápida (Faça nesta Ordem) <a class="header-anchor" href="#solucao-rapida-faca-nesta-ordem" aria-label="Permalink to &quot;Solução Rápida (Faça nesta Ordem)&quot;">​</a></h2><h3 id="passo-1-use-healthz-para-determinar-se-a-autenticacao-esta-bloqueando-voce" tabindex="-1">Passo 1: Use <code>/healthz</code> para Determinar &quot;Se a Autenticação Está Bloqueando Você&quot; <a class="header-anchor" href="#passo-1-use-healthz-para-determinar-se-a-autenticacao-esta-bloqueando-voce" aria-label="Permalink to &quot;Passo 1: Use `/healthz` para Determinar &quot;Se a Autenticação Está Bloqueando Você&quot;&quot;">​</a></h3><p><strong>Por Que</strong><code>all_except_health</code> permite que <code>/healthz</code> passe, mas bloqueia outras rotas; isso ajuda você a localizar rapidamente se 401 vem da camada de autenticação do proxy.</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"> # Sem nenhum Header de autenticação</span></span>\n<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">curl</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -i</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> http://127.0.0.1:8045/healthz</span></span></code></pre></div><p><strong>Você Deve Ver</strong></p><ul><li><code>auth_mode=all_except_health</code> (ou <code>auto</code> e <code>allow_lan_access=true</code>): geralmente retorna <code>200</code></li><li><code>auth_mode=strict</code>: retornará <code>401</code></li></ul><div class="tip custom-block"><p class="custom-block-title">/healthz é GET na Camada de Rota</p><p>O proxy registra <code>GET /healthz</code> na rota (veja <code>src-tauri/src/proxy/server.rs</code>).</p></div><hr><h3 id="passo-2-confirme-o-valor-efetivo-de-auth-mode-especialmente-auto" tabindex="-1">Passo 2: Confirme o &quot;Valor Efetivo&quot; de <code>auth_mode</code> (especialmente <code>auto</code>) <a class="header-anchor" href="#passo-2-confirme-o-valor-efetivo-de-auth-mode-especialmente-auto" aria-label="Permalink to &quot;Passo 2: Confirme o &quot;Valor Efetivo&quot; de `auth_mode` (especialmente `auto`)&quot;">​</a></h3><p><strong>Por Que</strong><code>auto</code> não é uma &quot;estratégia independente&quot;, ela calcula o modo que realmente será executado com base em <code>allow_lan_access</code>.</p><table tabindex="0"><thead><tr><th><code>proxy.auth_mode</code></th><th>Condição Adicional</th><th>Valor Efetivo</th></tr></thead><tbody><tr><td><code>off</code></td><td>-</td><td><code>off</code></td></tr><tr><td><code>strict</code></td><td>-</td><td><code>strict</code></td></tr><tr><td><code>all_except_health</code></td><td>-</td><td><code>all_except_health</code></td></tr><tr><td><code>auto</code></td><td><code>allow_lan_access=false</code></td><td><code>off</code></td></tr><tr><td><code>auto</code></td><td><code>allow_lan_access=true</code></td><td><code>all_except_health</code></td></tr></tbody></table><p><strong>Você pode verificar na página API Proxy da GUI</strong>: <code>Allow LAN Access</code> e <code>Auth Mode</code>.</p><hr><h3 id="passo-3-confirme-que-api-key-nao-esta-vazio-e-voce-esta-usando-o-mesmo-valor" tabindex="-1">Passo 3: Confirme que <code>api_key</code> Não Está Vazio e Você Está Usando o Mesmo Valor <a class="header-anchor" href="#passo-3-confirme-que-api-key-nao-esta-vazio-e-voce-esta-usando-o-mesmo-valor" aria-label="Permalink to &quot;Passo 3: Confirme que `api_key` Não Está Vazio e Você Está Usando o Mesmo Valor&quot;">​</a></h3><p><strong>Por Que</strong> Quando a autenticação está ativada, se <code>proxy.api_key</code> estiver vazio, <code>auth_middleware()</code> rejeitará diretamente todas as solicitações e registrará um erro de log.</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>Proxy auth is enabled but api_key is empty; denying request</span></span></code></pre></div><p><strong>Você Deve Ver</strong></p><ul><li>Na página API Proxy você pode ver uma key começando com <code>sk-</code> (o valor padrão em <code>ProxyConfig::default()</code> é gerado automaticamente)</li><li>Após clicar em &quot;Regenerate/Editar&quot; e salvar, solicitações externas serão verificadas imediatamente com a nova key (sem necessidade de reiniciar)</li></ul><hr><h3 id="passo-4-tente-com-o-header-mais-simples-nao-use-sdk-complexos-primeiro" tabindex="-1">Passo 4: Tente com o Header Mais Simples (Não Use SDK Complexos Primeiro) <a class="header-anchor" href="#passo-4-tente-com-o-header-mais-simples-nao-use-sdk-complexos-primeiro" aria-label="Permalink to &quot;Passo 4: Tente com o Header Mais Simples (Não Use SDK Complexos Primeiro)&quot;">​</a></h3><p><strong>Por Que</strong> O middleware lê primeiro <code>Authorization</code>, depois <code>x-api-key</code>, e finalmente <code>x-goog-api-key</code>. Se você enviar múltiplos Headers ao mesmo tempo, e o primeiro estiver errado, mesmo que o último esteja correto, não será usado.</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"> # Escrita recomendada: Authorization + Bearer</span></span>\n<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">curl</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -i</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> http://127.0.0.1:8045/v1/models</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> \\</span></span>\n<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">  -H</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> &quot;Authorization: Bearer sk-REPLACE_WITH_YOUR_PROXY_API_KEY&quot;</span></span></code></pre></div><p><strong>Você Deve Ver</strong>: <code>HTTP/1.1 200 OK</code> (ou pelo menos não mais 401)</p><div class="info custom-block"><p class="custom-block-title">Detalhes de Compatibilidade com Authorization do Proxy</p><p><code>auth_middleware()</code> fará um strip do valor de <code>Authorization</code> pelo prefixo <code>Bearer </code>; se não houver o prefixo <code>Bearer </code>, usará todo o valor como key para comparação. A documentação ainda recomenda <code>Authorization: Bearer &lt;key&gt;</code> (mais consistente com a convenção de SDKs gerais).</p></div><p><strong>Se Você Precisar Usar <code>x-api-key</code></strong>:</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">curl</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -i</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> http://127.0.0.1:8045/v1/models</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> \\</span></span>\n<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">  -H</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> &quot;x-api-key: sk-REPLACE_WITH_YOUR_PROXY_API_KEY&quot;</span></span></code></pre></div><hr><h2 id="armadilhas-comuns-ocorrem-realmente-no-codigo-fonte" tabindex="-1">Armadilhas Comuns (Ocorrem Realmente no Código-fonte) <a class="header-anchor" href="#armadilhas-comuns-ocorrem-realmente-no-codigo-fonte" aria-label="Permalink to &quot;Armadilhas Comuns (Ocorrem Realmente no Código-fonte)&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Fenômeno</th><th>Causa Real</th><th>Como Você Deve Corrigir</th></tr></thead><tbody><tr><td><code>auth_mode=auto</code>, mas chamadas locais ainda dão 401</td><td><code>allow_lan_access=true</code> faz <code>auto</code> se tornar <code>all_except_health</code></td><td>Desligue <code>allow_lan_access</code>, ou faça o cliente carregar a key</td></tr><tr><td>Você acha &quot;eu claramente trouxe x-api-key&quot;, mas ainda 401</td><td>Trouxe simultaneamente um <code>Authorization</code> incorreto, o middleware o usa por prioridade</td><td>Remova Headers extras, mantenha apenas aquele que você tem certeza que está correto</td></tr><tr><td><code>Authorization: Bearer&lt;key&gt;</code> ainda 401</td><td>Faltou espaço após <code>Bearer</code>, impossível fazer strip pelo prefixo <code>Bearer </code></td><td>Mude para <code>Authorization: Bearer &lt;key&gt;</code></td></tr><tr><td>Todas as solicitações dão 401, log mostra <code>api_key is empty</code></td><td><code>proxy.api_key</code> está vazio</td><td>Regere/defina uma key não vazia na GUI</td></tr></tbody></table><h2 id="resumo-da-licao" tabindex="-1">Resumo da Lição <a class="header-anchor" href="#resumo-da-licao" aria-label="Permalink to &quot;Resumo da Lição&quot;">​</a></h2><ul><li>Primeiro use <code>/healthz</code> para localizar se 401 vem da camada de autenticação do proxy</li><li>Depois confirme <code>auth_mode</code> (especialmente o modo efetivo de <code>auto</code>)</li><li>Finalmente, carregue apenas um Header correto para verificar (evite a armadilha de prioridade de Headers)</li></ul><h2 id="proximo-passo" tabindex="-1">Próximo Passo <a class="header-anchor" href="#proximo-passo" aria-label="Permalink to &quot;Próximo Passo&quot;">​</a></h2><blockquote><p>Na próxima lição aprenderemos <strong><a href="./../429-rotation/">429/Erros de Capacidade: Expectativas Corretas de Rotação de Contas e Equívocos de Esgotamento de Capacidade de Modelo</a></strong>.</p><p>Você aprenderá:</p><ul><li>Se 429 é &quot;cota insuficiente&quot; ou &quot;limitação upstream&quot;</li><li>Expectativas corretas de rotação de contas (quando muda automaticamente e quando não)</li><li>Usar configuração para reduzir a probabilidade de 429</li></ul></blockquote><hr><h2 id="apendice-referencia-do-codigo-fonte" tabindex="-1">Apêndice: Referência do Código-fonte <a class="header-anchor" href="#apendice-referencia-do-codigo-fonte" aria-label="Permalink to &quot;Apêndice: Referência do Código-fonte&quot;">​</a></h2><details><summary><strong>Clique para Expandir e Ver Localização do Código-fonte</strong></summary><blockquote><p>Última Atualização: 2026-01-23</p></blockquote><table tabindex="0"><thead><tr><th>Função</th><th>Caminho do Arquivo</th><th>Número da Linha</th></tr></thead><tbody><tr><td>Enumeração ProxyAuthMode</td><td><a href="https://github.com/lbjlaq/Antigravity-Manager/blob/main/src-tauri/src/proxy/config.rs#L5-L18" target="_blank" rel="noreferrer"><code>src-tauri/src/proxy/config.rs</code></a></td><td>5-18</td></tr><tr><td>ProxyConfig: allow_lan_access/auth_mode/api_key e Valores Padrão</td><td><a href="https://github.com/lbjlaq/Antigravity-Manager/blob/main/src-tauri/src/proxy/config.rs#L174-L258" target="_blank" rel="noreferrer"><code>src-tauri/src/proxy/config.rs</code></a></td><td>174-258</td></tr><tr><td>Resolução do Modo Auto (effective_auth_mode)</td><td><a href="https://github.com/lbjlaq/Antigravity-Manager/blob/main/src-tauri/src/proxy/security.rs#L1-L30" target="_blank" rel="noreferrer"><code>src-tauri/src/proxy/security.rs</code></a></td><td>1-30</td></tr><tr><td>Middleware de Autenticação (Extração e Prioridade de Header, Isenção /healthz, Permissão OPTIONS)</td><td><a href="https://github.com/lbjlaq/Antigravity-Manager/blob/main/src-tauri/src/proxy/middleware/auth.rs#L14-L77" target="_blank" rel="noreferrer"><code>src-tauri/src/proxy/middleware/auth.rs</code></a></td><td>14-77</td></tr><tr><td>Registro de Rota /healthz e Ordem de Middleware</td><td><a href="https://github.com/lbjlaq/Antigravity-Manager/blob/main/src-tauri/src/proxy/server.rs#L170-L193" target="_blank" rel="noreferrer"><code>src-tauri/src/proxy/server.rs</code></a></td><td>170-193</td></tr><tr><td>Documentação de Autenticação (Modos e Convenções de Cliente)</td><td><a href="https://github.com/lbjlaq/Antigravity-Manager/blob/main/docs/proxy/auth.md#L1-L45" target="_blank" rel="noreferrer"><code>docs/proxy/auth.md</code></a></td><td>1-45</td></tr></tbody></table><p><strong>Enumerações Chave</strong>:</p><ul><li><code>ProxyAuthMode::{Off, Strict, AllExceptHealth, Auto}</code>: Modos de Autenticação</li></ul><p><strong>Funções Chave</strong>:</p><ul><li><code>ProxySecurityConfig::effective_auth_mode()</code>: Converte <code>auto</code> em estratégia real</li><li><code>auth_middleware()</code>: Executa autenticação (inclui ordem de extração de Header e isenção /healthz)</li></ul></details>',45)])])}const m=a(i,[["render",d]]);export{h as __pageData,m as default};
